// Aggregate the week's bookings + new priority leads into an HTML digest.
const esc = (s) => String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const bookings = $('Search bookings (7d)').all().map(i => i.json).filter(r => r && r.id);
const leads = $('Search priority (7d)').all().map(i => i.json).filter(r => r && r.id);

function tally(rows, key) {
  const m = {};
  for (const r of rows) { const k = (r[key] || r.fields && r.fields[key] || 'Unknown'); m[k] = (m[k]||0)+1; }
  return Object.entries(m).sort((a,b)=>b[1]-a[1]);
}
const get = (r, k) => (r[k] != null ? r[k] : (r.fields ? r.fields[k] : undefined));
const norm = bookings.map(r => ({ City: get(r,'City')||'Unknown', Installer: get(r,'Installer')||'Unknown', utm: get(r,'UTM Source')||'' }));

const byCity = tally(norm, 'City');
const byInst = tally(norm, 'Installer');
const utmRows = norm.filter(r => r.utm);
const byUtm = tally(utmRows, 'utm');
const topUtm = byUtm.length ? `${byUtm[0][0]} (${byUtm[0][1]})` : 'direct / none tagged';

const rowsHtml = (pairs) => pairs.length
  ? pairs.map(([k,v]) => `<tr><td style="padding:4px 12px 4px 0">${esc(k)}</td><td style="padding:4px 0;text-align:right"><strong>${v}</strong></td></tr>`).join('')
  : `<tr><td style="padding:4px 0;color:#7c8472" colspan="2">none</td></tr>`;

const d = new Date();
const weekOf = d.toISOString().slice(0,10);
const subject = `Tuned Yota weekly digest — week of ${weekOf}`;
const html =
  `<div style="font-family:Arial,sans-serif;color:#3A2E26;max-width:560px;line-height:1.5">` +
  `<h2 style="color:#5B4B42">Weekly pulse — ${esc(weekOf)}</h2>` +
  `<p><strong>${bookings.length}</strong> new booking(s) · <strong>${leads.length}</strong> new priority-list lead(s) this week.</p>` +
  `<h3 style="color:#5B4B42;margin-bottom:4px">Bookings by city</h3><table>${rowsHtml(byCity)}</table>` +
  `<h3 style="color:#5B4B42;margin-bottom:4px">Bookings by installer</h3><table>${rowsHtml(byInst)}</table>` +
  `<p style="margin-top:14px">Top source: <strong>${esc(topUtm)}</strong></p>` +
  `<p style="color:#7c8472;font-size:13px">Operational pulse — the formal monthly summary still ships separately.</p>` +
  `</div>`;
const slackText = `:bar_chart: Weekly digest — ${bookings.length} booking(s), ${leads.length} new lead(s). Top source: ${topUtm}`;
return [{ json: { subject, html, slackText } }];
